/**
 * Function
 *
 * Defines a function in your own code the model can choose to call. Learn more about [function calling](https://platform.openai.com/docs/guides/function-calling).
 */
export const zFunctionTool = z.object({
  type: z.enum(['function']).default('function'),
  name: z.string(),
  description: z.union([z.string(), z.unknown()]).optional(),
  parameters: z.union([z.record(z.string(), z.unknown()), z.unknown()]),
  strict: z.union([z.boolean(), z.unknown()]),
  defer_loading: z.boolean().optional(),
})

/**
 * Function tool call
 *
 * A tool call to run a function. See the
 * [function calling guide](/docs/guides/function-calling) for more information.
 *
 */
export const zFunctionToolCall = z.object({
  id: z.string().optional(),
  type: z.enum(['function_call']),
  call_id: z.string(),
  namespace: z.string().optional(),
  name: z.string(),
  arguments: z.string(),
  status: z.enum(['in_progress', 'completed', 'incomplete']).optional(),
})

export const zFunctionToolCallResource = zFunctionToolCall.and(
  z.object({
    id: z.string(),
    status: zFunctionCallStatus,
    created_by: z.string().optional(),
  }),
)

export const zFunctionToolParam = z.object({
  name: z
    .string()
    .min(1)
    .max(128)
    .regex(/^[a-zA-Z0-9_-]+$/),
  description: z.union([z.string(), z.unknown()]).optional(),
  parameters: z.union([zEmptyModelParam, z.unknown()]).optional(),
  strict: z.union([z.boolean(), z.unknown()]).optional(),
  type: z.enum(['function']).default('function'),
  defer_loading: z.boolean().optional(),
})

